function recurseCodeFolder(plugin, folder) {
  const { app, settings } = plugin;
  const children = [...folder.children];
  children.sort((a, b) => {
    if (a instanceof import_obsidian7.TFolder && b instanceof import_obsidian7.TFile) return -1;
    if (a instanceof import_obsidian7.TFile && b instanceof import_obsidian7.TFolder) return 1;
    return a.name.localeCompare(b.name);
  });
  let text = "";
  for (const child of children) {
    if (child instanceof import_obsidian7.TFolder) {
      const tfolder = child;
      const hasCodeFiles = tfolder.children.some(
        (child2) => child2 instanceof import_obsidian7.TFile && child2.extension === "md"
      );
      if (!hasCodeFiles) continue;
      const childrenText = recurseCodeFolder(plugin, tfolder);
      text += `<li>\u{1F4C1} ${tfolder.name} ${childrenText}</li>`;
    } else if (child instanceof import_obsidian7.TFile) {
      const codeFile = child;
      const isTemplate = codeFile.path === settings.coding.folder + "/Template.md";
      const nonMarkdownFile = codeFile.extension !== "md";
      if (isTemplate || nonMarkdownFile) continue;
      const codeDesc = app.metadataCache.getFileCache(codeFile)?.frontmatter?.["code description"];
      const desc = codeDesc ? ": " + codeDesc : "";
      const htmlLink = `<a href="${codeFile.path}" class="internal-link">${codeFile.basename}</a>`;
      const codeAssignedCount = countTimesCodeIsAssigned(plugin, codeFile);
      text += `<li>\u{1F4C4} ${htmlLink} (${codeAssignedCount}x)${desc}</li>`;
    }
  }
  return `<ul>${text}</ul>`;
}
function processCodeOverviewCodeblock(plugin) {
  const { app, settings } = plugin;
  const codeFolder = app.vault.getFolderByPath(settings.coding.folder);
  if (!codeFolder) return `\u26A0\uFE0F Code folder "${settings.coding.folder}" not found.`;
  return recurseCodeFolder(plugin, codeFolder);
}

