  const { app } = plugin;
  const editor = getActiveEditor(app);
  const invalid = !editor || ambiguousSelection(editor) || selHasHighlightMarkup(editor) || activeFileHasInvalidName(app);
  if (invalid) return;
  if (typeOfFile(plugin) !== "Data File") {
    new import_obsidian11.Notice("You must be in a Data File to assign a code.", 4e3);
    return;
  }
  const dataFile = editor.editorComponent.view.file;
  if (!dataFile) {
    new import_obsidian11.Notice("No file open.", 4e3);
    return;
  }
  const paragraphText = editor.getLine(editor.getCursor().line);
