function unassignCodeWhileInDataFile(plugin, editor, dataFile, code) {
  const app = plugin.app;
  const cursor = editor.getCursor();
  const lineText = editor.getLine(cursor.line);
  const [blockId] = lineText.match(BLOCKID_REGEX) || [];
  if (!blockId) {
    new import_obsidian16.Notice("Cannot unassign code: no ID found at current line.", 0);
    return;
  }
  const updatedLine = lineText.replace(code.wikilink, "");
  editor.setLine(cursor.line, updatedLine);
  cursor.ch = Math.min(updatedLine.length - 1, cursor.ch);
  editor.setCursor(cursor);
  app.vault.process(code.tFile, (content) => {
    const codeFileLines = content.split("\n");
    const refInCodeFile = codeFileLines.findIndex((line) => {
      if (!line.includes(blockId)) return false;
      const linksInLine = line.match(new RegExp(WIKILINK_REGEX, "g")) || [];
      for (const wikilink of linksInLine) {
        const [_, innerlink] = wikilink.match(WIKILINK_REGEX) || [];
        if (!innerlink) continue;
        const linkedFile = app.metadataCache.getFirstLinkpathDest(innerlink, code.tFile.path);
        if (linkedFile?.path === dataFile.path) return true;
      }
      return false;
    });
    if (refInCodeFile < 0) {
      const msg = `"Code File "${code.tFile.basename}" contains no reference to Data File "${dataFile.basename}" with the ID "${blockId}". Reference in Code File is thus not deleted.`;
      new import_obsidian16.Notice(msg, 0);
      return content;
    }
    codeFileLines.splice(refInCodeFile, 1);
    content = codeFileLines.join("\n");
    new import_obsidian16.Notice(`Assignment of code "${code.tFile.basename}" removed.`, 3500);
    incrementProgress(plugin, "Code File", "unassign");
    return content;
  });
}
function unassignCodeCommand(plugin) {
  const app = plugin.app;
  const editor = getActiveEditor(app);
  if (!editor) return;
  if (typeOfFile(plugin) !== "Data File") {
    new import_obsidian16.Notice("You must be in a Data File to unassign a code.", 4e3);
    return;
  }
  const dataFile = editor.editorComponent.view.file;
  if (!dataFile) {
    new import_obsidian16.Notice("No file open.", 4e3);
    return;
  }
  const lnum = moveToLastLineOfParagraph(editor);
  const lineText = editor.getLine(lnum);
  const codesInPara = getCodesFilesInParagraphOfDatafile(plugin, dataFile, lineText);
  if (codesInPara.length === 0) {
    new import_obsidian16.Notice("Line does not contain any codes to remove.", 3500);
  } else if (codesInPara.length === 1) {
    unassignCodeWhileInDataFile(plugin, editor, dataFile, codesInPara[0]);
  } else {
    new SuggesterForCodeToUnassign(plugin, editor, dataFile, codesInPara).open();
  }
}

